SELECT *
FROM species_observations
WHERE species_id = 5 AND site_id = 10;

SELECT action_taken, date_initiated, status
FROM conservation_actions
WHERE responsible_user = 1;

SELECT users.username, conservation_actions.action_taken
FROM users
INNER JOIN conservation_actions ON users.user_id = conservation_actions.responsible_user;

SELECT site_name 
FROM observation_sites 
WHERE habitat_type = 'Wetland';

SELECT season_name
FROM seasons
WHERE season_name NOT IN (SELECT season FROM population_estimates);

SELECT DISTINCT species_id
FROM population_estimates
WHERE iba_criteria IN ('V', 'NT', 'EN');

SELECT *
FROM species_observations
JOIN users ON species_observations.observer_id = users.user_id;

SELECT AVG(population_at_site) AS average_population
FROM population_estimates
WHERE season = 'breeding';
